/**
 * Section filter – corresponds to main menu items that list movies.
 */
open class SectionFilter : AnimeFilter.Select<String>(
    "Section",
    arrayOf("All", "Movies", "Most Viewed", "Most Rating")
) {
    fun getPath(): String = when (state) {
        1 -> "movies"
        2 -> "most-viewed"
        3 -> "most-rating"
        else -> "" // "All" → homepage
    }
}

/**
 * Genre filter – multi‑select based on the site's taxonomy.
 */
open class GenreFilter : AnimeFilter.CheckBoxList<String>(
    "Genre",
    listOf(
        AnimeFilter.CheckBox("Parodies", "parodies"),
        AnimeFilter.CheckBox("Porn Movies", "porn-movies"),
        AnimeFilter.CheckBox("Uncategorized", "uncategorized")
    )
) {
    fun getActive(): List<String> = state.filter { it.state }.map { it.value }
}

